+    #[test]
+    fn actor_id_debug_clone_copy_ord_hash() {
+        use std::collections::HashSet;
+        let a = ActorId::new(1);
+        let b = ActorId::new(2);
+        let dbg = format!("{a:?}");
+        assert!(dbg.contains("ActorId"));
+        let _cloned = a.clone();
+        let _copied = a; // Copy
+        assert_eq!(a, a);
+        assert_ne!(a, b);
+        assert!(a < b);
+        let mut set = HashSet::new();
+        set.insert(a);
+        set.insert(b);
+        set.insert(a);
+        assert_eq!(set.len(), 2);
+    }
